# 打开浏览器，登录BOSS直聘
def login_bosszhipin():
    # 配置反爬浏览器
    options = ChromiumOptions()
    options.headless(False)
    options.set_argument('--start-maximized')
    pc_ua = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
    options.set_user_agent(pc_ua)
    options.set_argument('--no-sandbox')
    options.set_argument('--disable-gpu')
    options.auto_port() 
    print("🛠️ 正在初始化浏览器引擎...")
    page = ChromiumPage(options)
    print("✨ 浏览器初始化完毕，准备就绪！")
    try:
        print("🌐 浏览器即将打开，请在窗口弹出后进行扫码或验证码登录...")
        # 访问登录页
        page.get("https://www.zhipin.com/web/user/?ka=header-login") 
        print("💡 [提示] 请在打开的浏览器中手动登录 BOSS 直聘。")
        print("⏳ 我会在这里一直守护你，直到检测到登录跳转... ☕")
        initial_url = page.url
        timeout = 300  # 5分钟
        poll_interval = 2
        elapsed_time = 0
        login_flag = False
        while elapsed_time < timeout:
            current_url = page.url
            # 逻辑：如果 URL 发生了变化，通常意味着从登录页跳转到了首页或管理页
            if "login" not in current_url and current_url != initial_url:
                print("🎉 恭喜您，登录成功！")
                print("🚀 现在你可以最小化浏览器，剩下的繁琐工作交给我来处理就好啦~")
                login_flag = True
                break
            # 每隔 10 秒刷一个“等候中”的日志，防止控制台看起来像死掉了一样
            if elapsed_time % 10 == 0 and elapsed_time > 0:
                print(f"🕒 已经等待了 {elapsed_time} 秒，还在守候您的登录信号...")
            time.sleep(poll_interval)
            elapsed_time += poll_interval
        if login_flag:
            return {"result": "succeed", "page": page}
        else:
            print("⏰ 5分钟时间已到，您似乎还没有完成登录。")
            print("🛑 为了节省资源，我已自动安全关闭浏览器，请稍后重试。")
            page.quit() # 超时自动关闭是个好习惯
            return {"result": "failed", "failure": "Login not completed within timeout period."}        
    except Exception as e:
        print(f"🚨 糟糕，登录流程发生了意外中断: {e}")
        return {"result": "failed", "failure": str(e)}
        
#自动识别txt, pdf, word文档，并返回文本内容
def read_cv(local_cv_path: str) -> str:
    ext = os.path.splitext(local_cv_path)[1].lower()
    if ext == ".txt":
        with open(local_cv_path, "r", encoding="utf-8") as f:
            return f.read()
    elif ext == ".pdf":
        text = ""
        with fitz.open(local_cv_path) as doc:
            for page in doc:
                text += page.get_text("text")
        return text
    elif ext == ".docx":
        doc = docx.Document(local_cv_path)
        # 只提取非空段落并合并
        paras = [para.text for para in doc.paragraphs if para.text.strip()]
        return "\n".join(paras)
    else:
        raise ValueError(f"Unsupported file format: {ext}")

